253	/// Run all cases sequentially, dispatching each with per-case temp dir isolation.
254	pub fn rbtdre_run_cases(
255	    cases: &[rbtdre_Case],
256	    colors: &rbtdre_Colors,
257	    fail_fast: bool,
258	    root_temp: &Path,
259	) -> Result<rbtdre_RunResult, String> {
260	    let mut passed = 0usize;
261	    let mut failed = 0usize;
262	    let mut skipped = 0usize;
263	
264	    for case in cases {
265	        let case_dir = root_temp.join(case.name);
266	        std::fs::create_dir_all(&case_dir).map_err(|e| {
267	            format!("rbtd: failed to create case dir '{}': {}", case.name, e)
268	        })?;
269	
270	        let verdict = rbtdre_run_with_heartbeat(case, &case_dir);
271	        rbtdre_write_trace(&case_dir, case.name, &verdict);
272	
273	        match &verdict {
274	            rbtdre_Verdict::Pass => {
275	                crate::rbtdrg_info_now!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
276	                passed += 1;
277	            }
278	            rbtdre_Verdict::Fail(_) => {
279	                crate::rbtdrg_info_now!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
280	                failed += 1;
281	                if fail_fast {
282	                    break;
283	                }
284	            }
285	            rbtdre_Verdict::Skip(_) => {
286	                crate::rbtdrg_info_now!(
287	                    "{}SKIPPED:{} {}",
288	                    colors.yellow, colors.reset, case.name
289	                );
290	                skipped += 1;
291	            }
292	        }
293	    }
294	
295	    Ok(rbtdre_RunResult {
296	        passed,
297	        failed,
298	        skipped,
299	        temp_dir: root_temp.to_path_buf(),
300	    })
301	}
302	
303	/// Print colored summary line and trace directory location.
304	pub fn rbtdre_print_summary(result: &rbtdre_RunResult, colors: &rbtdre_Colors) {
305	    let total = result.passed + result.failed + result.skipped;
306	    let (color, end_color) = if result.failed > 0 {
307	        (colors.red, colors.reset)
308	    } else {
309	        (colors.green, colors.reset)
310	    };
311	
312	    crate::rbtdrg_info_now!(
313	        "{}{} passed, {} failed, {} skipped ({} total){}",
314	        color, result.passed, result.failed, result.skipped, total, end_color,
315	    );
316	    crate::rbtdrg_info_now!("Trace dir: {}", result.temp_dir.display());
317	}
318	
319	// ── Single-case operations ───────────────────────────────────
320	
321	/// Find a case by name in a flat case array.
322	pub fn rbtdre_find_case<'a>(
323	    cases: &'a [rbtdre_Case],
324	    target: &str,
325	) -> Option<&'a rbtdre_Case> {
326	    cases.iter().find(|c| c.name == target)
327	}
328	
329	/// List all cases by name.
330	pub fn rbtdre_list_cases(cases: &[rbtdre_Case]) {
331	    for case in cases {
332	        crate::rbtdrg_info_now!("  {}", case.name);
333	    }
334	}
335	
336	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
337	///
338	/// Expects the invocation context to already be installed in the thread-local
339	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
340	///
341	/// Setup failure short-circuits cases but still invokes teardown. Teardown
342	/// errors are surfaced as warnings via stderr; the function never panics on
343	/// teardown failure.
344	pub fn rbtdre_run_fixture(
345	    fixture: &'static rbtdre_Fixture,
346	    colors: &rbtdre_Colors,
347	    root_temp: &Path,
348	) -> Result<rbtdre_RunResult, String> {
349	    let setup_result = match fixture.setup {
350	        Some(f) => f(),
351	        None => Ok(()),
352	    };
353	
354	    let run_result = match setup_result {
355	        Ok(()) => {
356	            let fail_fast = rbtdre_resolve_fail_fast(fixture.disposition, false)
357	                .expect("disposition-default mode never fails policy resolution");
358	            rbtdre_run_cases(fixture.cases, colors, fail_fast, root_temp)
359	        }
360	        Err(msg) => Err(format!("rbtd: fixture '{}' setup failed: {}", fixture.name, msg)),
361	    };
362	
363	    if let Some(f) = fixture.teardown {
364	        f();
365	    }
366	
367	    run_result
368	}
369	
370	/// Run a single case without charge/quench lifecycle.
371	pub fn rbtdre_run_single_case(
372	    case: &rbtdre_Case,
373	    colors: &rbtdre_Colors,
374	    root_temp: &Path,
375	) -> Result<rbtdre_RunResult, String> {
376	    let case_dir = root_temp.join(case.name);
377	    std::fs::create_dir_all(&case_dir)
378	        .map_err(|e| format!("rbtd: failed to create case dir '{}': {}", case.name, e))?;
379	
380	    let verdict = rbtdre_run_with_heartbeat(case, &case_dir);
381	    rbtdre_write_trace(&case_dir, case.name, &verdict);
382	
383	    let (passed, failed, skipped) = match &verdict {
384	        rbtdre_Verdict::Pass => {
385	            crate::rbtdrg_info_now!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
386	            (1, 0, 0)
387	        }
388	        rbtdre_Verdict::Fail(_) => {
389	            crate::rbtdrg_info_now!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
390	            (0, 1, 0)
391	        }
392	        rbtdre_Verdict::Skip(_) => {
393	            crate::rbtdrg_info_now!("{}SKIPPED:{} {}", colors.yellow, colors.reset, case.name);
394	            (0, 0, 1)
395	        }
396	    };
397	
398	    Ok(rbtdre_RunResult {
399	        passed,
400	        failed,
401	        skipped,
402	        temp_dir: root_temp.to_path_buf(),
403	    })
404	}
