211	// ── Lexer ───────────────────────────────────────────────────
212	
213	/// Read one shell word starting at `*i`, advancing `*i` past it and `*line`
214	/// over any embedded newlines. Quoted segments and `${...}` parameter
215	/// expansions are consumed as part of the word; an embedded `$(` command
216	/// substitution STOPS the word so the caller's lexer scans the substituted
217	/// command at its own command position.
218	pub(crate) fn zrbtdru_read_word(chars: &[char], i: &mut usize, line: &mut usize) -> String {
219	    let n = chars.len();
220	    let mut word = String::new();
221	    while *i < n {
222	        let c = chars[*i];
223	        match c {
224	            ' ' | '\t' | '\r' | '\n' => break,
225	            ';' | '|' | '&' | '<' | '>' | '(' | ')' | '`' | '#' => break,
226	            '\'' => {
227	                word.push(c);
228	                *i += 1;
229	                while *i < n && chars[*i] != '\'' {
230	                    if chars[*i] == '\n' {
231	                        *line += 1;
232	                    }
233	                    word.push(chars[*i]);
234	                    *i += 1;
235	                }
236	                if *i < n {
237	                    word.push(chars[*i]);
238	                    *i += 1;
239	                }
240	            }
241	            '"' => {
242	                word.push(c);
243	                *i += 1;
244	                while *i < n && chars[*i] != '"' {
245	                    if chars[*i] == '\\' && *i + 1 < n {
246	                        word.push(chars[*i]);
247	                        word.push(chars[*i + 1]);
248	                        *i += 2;
249	                        continue;
250	                    }
251	                    if chars[*i] == '\n' {
252	                        *line += 1;
253	                    }
254	                    word.push(chars[*i]);
255	                    *i += 1;
256	                }
257	                if *i < n {
258	                    word.push(chars[*i]);
259	                    *i += 1;
260	                }
261	            }
262	            '$' if *i + 1 < n && chars[*i + 1] == '(' => break,
263	            '$' if *i + 1 < n && chars[*i + 1] == '{' => {
264	                word.push('$');
265	                *i += 1;
266	                let mut depth = 0usize;
267	                while *i < n {
268	                    let d = chars[*i];
269	                    if d == '\n' {
270	                        *line += 1;
271	                    }
272	                    word.push(d);
273	                    *i += 1;
274	                    if d == '{' {
275	                        depth += 1;
276	                    } else if d == '}' {
277	                        depth -= 1;
278	                        if depth == 0 {
279	                            break;
280	                        }
281	                    }
282	                }
283	            }
284	            _ => {
285	                word.push(c);
286	                *i += 1;
287	            }
288	        }
289	    }
290	    word
291	}
292	
293	/// Classify a word as transparent or value-introducing when it sits in command
294	/// position. `Some(true)` — a keyword whose successor is itself a command
295	/// (`if`, `then`, `while`, …). `Some(false)` — a keyword whose successor is a
296	/// value, not a command (`for`, `case`, `in`, …). `None` — not a keyword.
297	pub(crate) fn zrbtdru_keyword_kind(word: &str) -> Option<bool> {
298	    match word {
299	        "if" | "elif" | "while" | "until" | "then" | "else" | "do" | "!"
300	        | "time" | "fi" | "done" | "esac" => Some(true),
301	        "for" | "select" | "case" | "in" | "function" => Some(false),
302	        _ => None,
303	    }
304	}
305	
306	/// True when `word` is a `NAME=`, `NAME+=`, or `NAME[idx]=` assignment prefix —
307	/// a command may still follow on the same line (`FOO=bar cmd`), so command
308	/// position is preserved across it.
309	pub(crate) fn zrbtdru_is_assignment(word: &str) -> bool {
310	    let bytes = word.as_bytes();
311	    if bytes.is_empty() {
312	        return false;
313	    }
314	    let first = bytes[0] as char;
315	    if !(first.is_ascii_alphabetic() || first == '_') {
316	        return false;
317	    }
318	    let mut k = 1;
319	    while k < bytes.len() {
320	        let ch = bytes[k] as char;
321	        if ch == '=' {
322	            return true;
323	        }
324	        if ch == '+' && k + 1 < bytes.len() && bytes[k + 1] == b'=' {
325	            return true;
326	        }
327	        if ch == '[' {
328	            return word.contains("]=");
329	        }
330	        if !(ch.is_ascii_alphanumeric() || ch == '_') {
331	            return false;
332	        }
333	        k += 1;
334	    }
335	    false
336	}
337	
338	/// Advance `*i` past a balanced run of parentheses, tracking newlines in
339	/// `*line`. `depth` is the count of opening parens already consumed by the
340	/// caller; scanning ends when it returns to zero. Quoted segments are skipped
341	/// so parens inside strings do not affect the balance — covering array literals
342	/// `NAME=( … )` and nested arithmetic `$(( ( … ) ))`.
343	pub(crate) fn zrbtdru_skip_balanced_parens(chars: &[char], i: &mut usize, line: &mut usize, mut depth: usize) {
344	    let n = chars.len();
345	    while *i < n && depth > 0 {
346	        match chars[*i] {
347	            '(' => depth += 1,
348	            ')' => depth -= 1,
349	            '\n' => *line += 1,
350	            '\'' => {
351	                *i += 1;
352	                while *i < n && chars[*i] != '\'' {
353	                    if chars[*i] == '\n' {
354	                        *line += 1;
355	                    }
356	                    *i += 1;
357	                }
358	            }
359	            '"' => {
360	                *i += 1;
361	                while *i < n && chars[*i] != '"' {
362	                    if chars[*i] == '\\' && *i + 1 < n {
363	                        *i += 2;
364	                        continue;
365	                    }
366	                    if chars[*i] == '\n' {
367	                        *line += 1;
368	                    }
369	                    *i += 1;
370	                }
371	            }
372	            _ => {}
373	        }
374	        *i += 1;
375	    }
376	}
377	
378	/// Extract every command-position token from a bash source string, paired with
379	/// its 1-based line number. A token is in command position at the start of the
380	/// script and after any command separator (`;`, `|`, `&`, `&&`, `||`, newline,
381	/// `(`, `$(`, `` ` ``, an open brace group) and after a transparent keyword.
382	/// Assignments, redirections, `[[ ]]` test contents, comments, here-doc bodies,
383	/// and arithmetic `(( ))` / `$(( ))` are excluded.
384	pub(crate) fn zrbtdru_command_words(src: &str) -> Vec<(usize, String)> {
385	    let chars: Vec<char> = src.chars().collect();
386	    let n = chars.len();
387	    let mut out: Vec<(usize, String)> = Vec::new();
388	    let mut i = 0usize;
389	    let mut line = 1usize;
390	    let mut cmd_pos = true;
391	    let mut paren_depth = 0usize;
392	    let mut in_dbracket = false;
393	    let mut pending_heredoc: Option<String> = None;
394	    // case…esac nesting. Each frame tracks the position within a `case`:
395	    // 0 = subject (between `case` and `in`), 1 = pattern (suppress recording;
396	    // `|` is alternation, not a pipe), 2 = branch body (record commands).
397	    let mut case_stack: Vec<u8> = Vec::new();
398	
399	    while i < n {
400	        let c = chars[i];
401	
402	        if c == '\n' {
403	            i += 1;
404	            line += 1;
405	            cmd_pos = true;
406	            if let Some(delim) = pending_heredoc.take() {
407	                loop {
408	                    let start = i;
409	                    while i < n && chars[i] != '\n' {
410	                        i += 1;
411	                    }
412	                    let body: String = chars[start..i].iter().collect();
413	                    let had_nl = i < n;
414	                    if had_nl {
415	                        i += 1;
416	                        line += 1;
417	                    }
418	                    if body.trim() == delim {
419	                        break;
420	                    }
421	                    if !had_nl {
422	                        break;
423	                    }
424	                }
425	            }
426	            continue;
427	        }
428	        if c == ' ' || c == '\t' || c == '\r' {
429	            i += 1;
430	            continue;
431	        }
432	        if c == '\\' && i + 1 < n && chars[i + 1] == '\n' {
433	            i += 2;
434	            line += 1;
435	            continue;
436	        }
437	        if c == '#' {
438	            while i < n && chars[i] != '\n' {
439	                i += 1;
440	            }
441	            continue;
442	        }
443	        if c == ';' {
444	            i += 1;
445	            if i < n && chars[i] == ';' {
446	                i += 1;
447	                // `;;` ends a case branch — the next token opens a new pattern.
448	                if let Some(top) = case_stack.last_mut() {
449	                    *top = 1;
450	                }
451	                cmd_pos = false;
452	                continue;
453	            }
454	            if !in_dbracket {
455	                cmd_pos = true;
456	            }
457	            continue;
458	        }
459	        if c == '|' {
460	            i += 1;
461	            if i < n && chars[i] == '|' {
462	                i += 1;
463	            }
464	            // Within a case pattern `|` is alternation, not a pipe.
465	            if case_stack.last() == Some(&1) {
466	                continue;
467	            }
468	            if !in_dbracket {
469	                cmd_pos = true;
470	            }
471	            continue;
472	        }
473	        if c == '&' {
474	            if i + 1 < n && chars[i + 1] == '>' {
475	                i += 2;
476	                if i < n && chars[i] == '>' {
477	                    i += 1;
478	                }
479	                cmd_pos = false;
480	                continue;
481	            }
482	            i += 1;
483	            if i < n && chars[i] == '&' {
484	                i += 1;
485	            }
486	            if !in_dbracket {
487	                cmd_pos = true;
488	            }
489	            continue;
490	        }
491	        if c == '<' {
492	            if i + 1 < n && chars[i + 1] == '<' {
493	                if i + 2 < n && chars[i + 2] == '<' {
494	                    i += 3;
495	                    cmd_pos = false;
496	                    continue;
497	                }
498	                i += 2;
499	                if i < n && chars[i] == '-' {
500	                    i += 1;
501	                }
502	                while i < n && (chars[i] == ' ' || chars[i] == '\t') {
503	                    i += 1;
504	                }
505	                let mut delim = String::new();
506	                let quote = if i < n && (chars[i] == '\'' || chars[i] == '"') {
507	                    let q = chars[i];
508	                    i += 1;
509	                    Some(q)
510	                } else {
511	                    None
512	                };
513	                while i < n {
514	                    let d = chars[i];
515	                    match quote {
516	                        Some(qc) => {
517	                            if d == qc {
518	                                i += 1;
519	                                break;
520	                            }
521	                            delim.push(d);
522	                            i += 1;
523	                        }
524	                        None => {
525	                            if d == ' ' || d == '\t' || d == '\n' || d == ';'
526	                                || d == '&' || d == '|' || d == '<' || d == '>'
527	                                || d == '(' || d == ')'
528	                            {
529	                                break;
530	                            }
531	                            if d == '\\' {
532	                                i += 1;
533	                                continue;
534	                            }
535	                            delim.push(d);
536	                            i += 1;
537	                        }
538	                    }
539	                }
540	                if !delim.is_empty() {
541	                    pending_heredoc = Some(delim);
542	                }
543	                cmd_pos = false;
544	                continue;
545	            }
546	            i += 1;
547	            if i < n && chars[i] == '&' {
548	                i += 1;
549	            }
550	            cmd_pos = false;
551	            continue;
552	        }
553	        if c == '>' {
554	            i += 1;
555	            if i < n && (chars[i] == '>' || chars[i] == '&') {
556	                i += 1;
557	            }
558	            cmd_pos = false;
559	            continue;
560	        }
561	        if c == '(' {
562	            if i + 1 < n && chars[i + 1] == '(' {
563	                // Arithmetic `(( … ))` — not a command list.
564	                i += 2;
565	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
566	                cmd_pos = false;
567	                continue;
568	            }
569	            i += 1;
570	            paren_depth += 1;
571	            cmd_pos = true;
572	            continue;
573	        }
574	        if c == ')' {
575	            i += 1;
576	            if paren_depth > 0 {
577	                paren_depth -= 1;
578	                cmd_pos = false;
579	            } else if case_stack.last() == Some(&1) {
580	                // Pattern terminator — the branch body's command list follows.
581	                if let Some(top) = case_stack.last_mut() {
582	                    *top = 2;
583	                }
584	                cmd_pos = true;
585	            } else {
586	                cmd_pos = true;
587	            }
588	            continue;
589	        }
590	        if c == '`' {
591	            i += 1;
592	            cmd_pos = true;
593	            continue;
594	        }
595	        if c == '$' {
596	            if i + 1 < n && chars[i + 1] == '(' {
597	                if i + 2 < n && chars[i + 2] == '(' {
598	                    // Arithmetic substitution `$(( … ))` — not a command.
599	                    i += 3;
600	                    zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 2);
601	                    cmd_pos = false;
602	                    continue;
603	                }
604	                i += 2;
605	                paren_depth += 1;
606	                cmd_pos = true;
607	                continue;
608	            }
609	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
610	            cmd_pos = false;
611	            continue;
612	        }
613	        if c == '{' {
614	            if i + 1 < n && (chars[i + 1] == ' ' || chars[i + 1] == '\t' || chars[i + 1] == '\n') {
615	                i += 1;
616	                cmd_pos = true;
617	                continue;
618	            }
619	            let _ = zrbtdru_read_word(&chars, &mut i, &mut line);
620	            cmd_pos = false;
621	            continue;
622	        }
623	        if c == '}' {
624	            i += 1;
625	            continue;
626	        }
627	
628	        let word_line = line;
629	        let word = zrbtdru_read_word(&chars, &mut i, &mut line);
630	        if word.is_empty() {
631	            i += 1;
632	            continue;
633	        }
634	        if word == "[[" {
635	            if cmd_pos {
636	                in_dbracket = true;
637	            }
638	            cmd_pos = false;
639	            continue;
640	        }
641	        if word == "]]" {
642	            in_dbracket = false;
643	            cmd_pos = false;
644	            continue;
645	        }
646	        if in_dbracket {
647	            continue;
648	        }
649	        // case…esac structure — tracked regardless of command position so that
650	        // branch patterns (which sit at command position) are not mistaken for
651	        // commands.
652	        if word == "case" {
653	            case_stack.push(0);
654	            cmd_pos = false;
655	            continue;
656	        }
657	        if word == "esac" {
658	            case_stack.pop();
659	            cmd_pos = false;
660	            continue;
661	        }
662	        if word == "in" && case_stack.last() == Some(&0) {
663	            if let Some(top) = case_stack.last_mut() {
664	                *top = 1;
665	            }
666	            cmd_pos = false;
667	            continue;
668	        }
669	        if case_stack.last() == Some(&1) {
670	            // Matching a case pattern — suppress; the pattern is not a command.
671	            cmd_pos = false;
672	            continue;
673	        }
674	        if !cmd_pos {
675	            continue;
676	        }
677	        if zrbtdru_is_assignment(&word) {
678	            // `NAME=( … )` array literal — the elements are data, not commands.
679	            let mut j = i;
680	            while j < n && (chars[j] == ' ' || chars[j] == '\t') {
681	                j += 1;
682	            }
683	            if j < n && chars[j] == '(' {
684	                i = j + 1;
685	                zrbtdru_skip_balanced_parens(&chars, &mut i, &mut line, 1);
686	            }
687	            continue;
688	        }
689	        match zrbtdru_keyword_kind(&word) {
690	            Some(true) => continue,
691	            Some(false) => {
692	                cmd_pos = false;
693	                continue;
694	            }
695	            None => {}
696	        }
697	        out.push((word_line, word));
698	        cmd_pos = false;
699	    }
700	    out
701	}
