703	// ── Function collection and classification ──────────────────
704	
705	/// Harvest locally-defined function names from one source into `out`. Matches
706	/// both `name() {` and `function name` forms.
707	pub(crate) fn zrbtdru_collect_functions(src: &str, out: &mut BTreeSet<String>) {
708	    for raw in src.lines() {
709	        let trimmed = raw.trim_start();
710	        let rest = if let Some(after) = trimmed.strip_prefix("function ") {
711	            after.trim_start()
712	        } else {
713	            trimmed
714	        };
715	        let mut name = String::new();
716	        for ch in rest.chars() {
717	            if ch.is_ascii_alphanumeric() || ch == '_' || ch == '-' {
718	                name.push(ch);
719	            } else {
720	                break;
721	            }
722	        }
723	        if name.is_empty() {
724	            continue;
725	        }
726	        let after_name = rest[name.len()..].trim_start();
727	        if after_name.starts_with("()") || trimmed.starts_with("function ") {
728	            out.insert(name);
729	        }
730	    }
731	}
