733	/// Classify a command-position token. Returns `Some(detail)` when it violates
734	/// the domain's discipline, `None` when it is permitted. Dynamic tokens
735	/// (containing an expansion or quote) cannot be statically named and are
736	/// skipped.
737	pub(crate) fn zrbtdru_classify(
738	    command: &str,
739	    locals: &BTreeSet<String>,
740	    domain: zrbtdru_Domain,
741	) -> Option<String> {
742	    if command.is_empty() {
743	        return None;
744	    }
745	    if command.contains('$')
746	        || command.contains('`')
747	        || command.contains('"')
748	        || command.contains('\'')
749	    {
750	        return None;
751	    }
752	    let base = command.rsplit('/').next().unwrap_or(command);
753	    if ZRBTDRU_BUILTINS.contains(&base) {
754	        return None;
755	    }
756	    if locals.contains(command) || locals.contains(base) {
757	        return None;
758	    }
759	    // POSIX floor is universal — cleared in both domains.
760	    if ZRBTDRU_POSIX_FLOOR.contains(&base) {
761	        return None;
762	    }
763	    match domain {
764	        zrbtdru_Domain::Kit => {
765	            if ZRBTDRU_DECLARED_DEPS.contains(&base) {
766	                return None;
767	            }
768	            for ev in ZRBTDRU_EVICTIONS {
769	                if ev.command == base {
770	                    return Some(format!("evicted command — use {}", ev.replacement));
771	                }
772	            }
773	            Some("unknown command — not in POSIX floor or RBS0 declared dependencies".to_string())
774	        }
775	        zrbtdru_Domain::Gcb => {
776	            // No declared-dep inheritance and no eviction free-pass: GCB-bash is
777	            // held to floor ∪ the curated container-tool list (supply-chain).
778	            if ZRBTDRU_GCB_ALLOWED.contains(&base) {
779	                return None;
780	            }
781	            Some("unknown command — not in the curated GCB container-tool allowlist".to_string())
782	        }
783	    }
784	}
785	
786	/// True when `command` names an external command in the corpus's surface — a
787	/// static token that is neither a bash builtin nor a locally-defined function.
788	/// This is the classification-independent inventory predicate: it admits the
789	/// union of allowed externals (floor / declared / gcb-extra / tolerated
790	/// evictions) AND violations. Dynamic tokens (expansion or quote) cannot be
791	/// statically named and are excluded.
792	fn zrbtdru_is_external(command: &str, locals: &BTreeSet<String>) -> bool {
793	    if command.is_empty()
794	        || command.contains('$')
795	        || command.contains('`')
796	        || command.contains('"')
797	        || command.contains('\'')
798	    {
799	        return false;
800	    }
801	    let base = command.rsplit('/').next().unwrap_or(command);
802	    !ZRBTDRU_BUILTINS.contains(&base)
803	        && !locals.contains(command)
804	        && !locals.contains(base)
805	}
806	
807	/// One domain scan: violations, plus the full external-command inventory (base
808	/// command names, deduplicated and sorted) — the empirical basis for curating
809	/// an allowlist.
810	struct zrbtdru_ScanResult {
811	    findings: Vec<zrbtdru_Finding>,
812	    inventory: BTreeSet<String>,
813	}
814	
815	// ── Corpus walk and scan ────────────────────────────────────
816	
817	/// Recursively collect every `*.sh` file under `dir` into `out`, skipping any
818	/// subdirectory whose basename begins with one of `excluded_prefixes`.
819	fn zrbtdru_walk_sh(dir: &Path, excluded_prefixes: &[&str], out: &mut Vec<PathBuf>) {
820	    let entries = match std::fs::read_dir(dir) {
821	        Ok(e) => e,
822	        Err(_) => return,
823	    };
824	    for entry in entries.flatten() {
825	        let path = entry.path();
826	        if path.is_dir() {
827	            let excluded = path
828	                .file_name()
829	                .and_then(|s| s.to_str())
830	                .map(|name| {
831	                    excluded_prefixes
832	                        .iter()
833	                        .any(|prefix| name.starts_with(prefix))
834	                })
835	                .unwrap_or(false);
836	            if excluded {
837	                continue;
838	            }
839	            zrbtdru_walk_sh(&path, excluded_prefixes, out);
840	        } else if path.extension().and_then(|e| e.to_str()) == Some(ZRBTDRU_SH_EXT) {
841	            out.push(path);
842	        }
843	    }
844	}
845	
846	/// True when `path` lies under a Google Cloud Build job directory (any path
847	/// component beginning with the rbgj prefix).
848	fn zrbtdru_is_gcb(path: &Path) -> bool {
849	    path.components().any(|comp| {
850	        comp.as_os_str()
851	            .to_str()
852	            .map(|s| s.starts_with(ZRBTDRU_GCB_DIR_PREFIX))
853	            .unwrap_or(false)
854	    })
855	}
856	
857	/// Walk the corpus, collect functions across all of it, then scan the files
858	/// belonging to `domain`, returning every finding (sorted by file and line)
859	/// plus the domain's external-command inventory.
860	fn zrbtdru_scan_domain(tools: &Path, domain: zrbtdru_Domain) -> Result<zrbtdru_ScanResult, String> {
861	    // Pass 1 — function-visibility universe. Walk every kit so cross-kit and
862	    // sourced function names resolve (e.g. rbk's Windows handbook sources jjk's
863	    // zipper); only dead ABANDONED code stays invisible.
864	    let mut universe_files: Vec<PathBuf> = Vec::new();
865	    zrbtdru_walk_sh(tools, ZRBTDRU_UNIVERSE_EXCLUDED_DIR_PREFIXES, &mut universe_files);
866	    universe_files.sort();
867	
868	    let mut locals: BTreeSet<String> = BTreeSet::new();
869	    for f in &universe_files {
870	        let src = std::fs::read_to_string(f)
871	            .map_err(|e| format!("read {} failed: {}", f.display(), e))?;
872	        zrbtdru_collect_functions(&src, &mut locals);
873	    }
874	
875	    // Pass 2 — lint target. Only the release kit roots, minus dead/not-yet-live.
876	    let mut lint_files: Vec<PathBuf> = Vec::new();
877	    for kit in ZRBTDRU_KIT_ROOTS {
878	        zrbtdru_walk_sh(&tools.join(kit), ZRBTDRU_LINT_EXCLUDED_DIR_PREFIXES, &mut lint_files);
879	    }
880	    lint_files.sort();
881	
882	    let root = tools.parent().unwrap_or(tools);
883	    let mut findings: Vec<zrbtdru_Finding> = Vec::new();
884	    let mut inventory: BTreeSet<String> = BTreeSet::new();
885	    for path in &lint_files {
886	        let is_gcb = zrbtdru_is_gcb(path);
887	        let in_domain = match domain {
888	            zrbtdru_Domain::Kit => !is_gcb,
889	            zrbtdru_Domain::Gcb => is_gcb,
890	        };
891	        if !in_domain {
892	            continue;
893	        }
894	        let src = std::fs::read_to_string(path)
895	            .map_err(|e| format!("read {} failed: {}", path.display(), e))?;
896	        let rel = path.strip_prefix(root).unwrap_or(path).display().to_string();
897	        for (line, command) in zrbtdru_command_words(&src) {
898	            if zrbtdru_is_external(&command, &locals) {
899	                let base = command.rsplit('/').next().unwrap_or(&command);
900	                inventory.insert(base.to_string());
901	            }
902	            if let Some(detail) = zrbtdru_classify(&command, &locals, domain) {
903	                findings.push(zrbtdru_Finding {
904	                    file: rel.clone(),
905	                    line,
906	                    command,
907	                    detail,
908	                });
909	            }
910	        }
911	    }
912	    Ok(zrbtdru_ScanResult { findings, inventory })
913	}
914	
915	/// Render findings as a stable one-per-line report.
916	fn zrbtdru_render(findings: &[zrbtdru_Finding]) -> String {
917	    let mut report = String::new();
918	    for f in findings {
919	        report.push_str(&format!("{}:{}: {} — {}\n", f.file, f.line, f.command, f.detail));
920	    }
921	    report
922	}
923	
924	/// Drive one domain's scan, persist a findings trace into the case dir, and
925	/// fail the verdict when any violation remains.
926	fn zrbtdru_run_domain(dir: &Path, domain: zrbtdru_Domain, label: &str) -> rbtdre_Verdict {
927	    let root = match std::env::current_dir() {
928	        Ok(r) => r,
929	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
930	    };
931	    let tools = root.join(ZRBTDRU_TOOLS_SUBDIR);
932	    let scan = match zrbtdru_scan_domain(&tools, domain) {
933	        Ok(s) => s,
934	        Err(e) => return rbtdre_Verdict::Fail(e),
935	    };
936	    let findings = &scan.findings;
937	    let report = zrbtdru_render(findings);
938	    let findings_name = format!("{}{}{}", ZRBTDRU_TRACE_PREFIX, label, ZRBTDRU_FINDINGS_SUFFIX);
939	    let _ = std::fs::write(dir.join(findings_name), &report);
940	
941	    let mut inventory_report = String::new();
942	    for cmd in &scan.inventory {
943	        inventory_report.push_str(cmd);
944	        inventory_report.push('\n');
945	    }
946	    let inventory_name = format!("{}{}{}", ZRBTDRU_TRACE_PREFIX, label, ZRBTDRU_INVENTORY_SUFFIX);
947	    let _ = std::fs::write(dir.join(inventory_name), &inventory_report);
948	
949	    if findings.is_empty() {
950	        rbtdre_Verdict::Pass
951	    } else {
952	        rbtdre_Verdict::Fail(format!(
953	            "{} BCG command-discipline violation(s) in {}-bash:\n{}",
954	            findings.len(),
955	            label,
956	            report
957	        ))
958	    }
959	}
960	
961	// ── Cases and fixture ───────────────────────────────────────
962	
963	fn rbtdru_kit_bash(dir: &Path) -> rbtdre_Verdict {
964	    zrbtdru_run_domain(dir, zrbtdru_Domain::Kit, ZRBTDRU_LABEL_KIT)
965	}
966	
967	fn rbtdru_gcb_bash(dir: &Path) -> rbtdre_Verdict {
968	    zrbtdru_run_domain(dir, zrbtdru_Domain::Gcb, ZRBTDRU_LABEL_GCB)
969	}
970	
971	pub static RBTDRU_CASES_CUPEL: &[rbtdre_Case] = &[
972	    case!(rbtdru_kit_bash),
973	    case!(rbtdru_gcb_bash),
974	];
975	
976	pub static RBTDRU_FIXTURE_CUPEL: rbtdre_Fixture = rbtdre_Fixture {
977	    name: RBTDRM_FIXTURE_CUPEL,
978	    disposition: rbtdre_Disposition::Independent,
979	    setup: None,
980	    teardown: None,
981	    cases: RBTDRU_CASES_CUPEL,
982	};
983

