fn zrbtdrn_render(hits: &[zrbtdrn_Hit]) -> String {
    let mut report = String::new();
    for h in hits {
        report.push_str(&format!("{}:{}: {} — {}\n", h.path, h.line, h.token, h.line_text.trim()));
    }
    report
}

